create table dirkspzm32.ctl_service_io (
    service_name   varchar2(200 char) not null enable,
    sid            varchar2(2 char) default '01' not null enable,
    firma_nr       number(6, 0) default 1,
    interval_sec   number(5, 0) default 600,
    client_command varchar2(30 char),
    status         varchar2(50 char),
    info_debug     varchar2(4000 char),
    message_code   number(5, 0),
    message_text   varchar2(255 char),
    erz_datum      date default sysdate,
    erz_login_id   number(*, 0),
    aend_datum     date,
    aend_login_id  number(*, 0)
);


